305→function sliderThumbCenterPercent(
306→  valuePct: number,
307→  trackPx: number,
308→  thumbPx: number,
309→): string {
310→  const clamped = Math.max(0, Math.min(100, valuePct));
311→  const min = thumbPx * 0.5;
312→  const max = Math.max(min, trackPx - thumbPx * 0.5);
313→  const center = min + ((max - min) * clamped) / 100;
314→  return `${(center / trackPx) * 100}%`;
315→}
