469→async function loadDataUrlImage(url: string): Promise<HTMLImageElement> {
470→  const cached = decodedImageCache.get(url);
471→  if (cached) return cached;
472→  const promise = new Promise<HTMLImageElement>((resolve, reject) => {
473→    const img = new Image();
474→    img.onload = () => resolve(img);
475→    img.onerror = () => reject(new Error(`Failed to load image ${url}`));
476→    img.src = url;
477→  });
478→  decodedImageCache.set(url, promise);
479→  return promise;
480→}
