482→async function cropFrameRowToDataUrl(
483→  src: string,
484→  atlasRows = 1,
485→  atlasRow = 0,
486→): Promise<CroppedFrameRowResult> {
487→  const key = `${src}|${atlasRows}|${atlasRow}`;
488→  const cached = croppedFrameRowCache.get(key);
489→  if (cached) return cached;
490→
491→  const promise = (async () => {
492→    const img = await loadDataUrlImage(src);
493→    const rows = Math.max(1, Math.floor(atlasRows));
494→    const rowHeight = Math.max(1, Math.floor(img.height / rows));
495→    const rowIndex = Math.max(0, Math.min(rows - 1, Math.floor(atlasRow)));
496→    const srcY = rowIndex * rowHeight;
497→
498→    const rowCanvas = document.createElement("canvas");
499→    rowCanvas.width = img.width;
500→    rowCanvas.height = rowHeight;
501→    const rowCtx = rowCanvas.getContext("2d");
502→    if (!rowCtx) {
503→      return { url: src, width: img.width, height: rowHeight };
504→    }
505→
506→    rowCtx.clearRect(0, 0, rowCanvas.width, rowCanvas.height);
507→    rowCtx.drawImage(
508→      img,
509→      0,
510→      srcY,
511→      img.width,
512→      rowHeight,
513→      0,
514→      0,
515→      img.width,
516→      rowHeight,
517→    );
518→    // Keep the full row including transparent gutters.
519→    // Template offsets are authored against the uncropped backdrop texture space.
520→    return {
521→      url: rowCanvas.toDataURL("image/png"),
522→      width: rowCanvas.width,
523→      height: rowCanvas.height,
524→    };
525→  })();
526→
527→  croppedFrameRowCache.set(key, promise);
528→  return promise;
529→}
