546→    const sw = Math.max(1, Math.min(img.width - sx, Math.floor(width)));
547→    const sh = Math.max(1, Math.min(img.height - sy, Math.floor(height)));
548→    const cropCanvas = document.createElement("canvas");
549→    cropCanvas.width = sw;
550→    cropCanvas.height = sh;
551→    const cropCtx = cropCanvas.getContext("2d");
552→    if (!cropCtx) return src;
553→    cropCtx.clearRect(0, 0, sw, sh);
554→    cropCtx.drawImage(img, sx, sy, sw, sh, 0, 0, sw, sh);
555→    return cropCanvas.toDataURL("image/png");
556→  })();
557→
558→  croppedImageRegionCache.set(key, promise);
559→  return promise;
