588→function rotateCellClockwise(
589→  atlas: HTMLImageElement,
590→  cellIndex: number,
591→  cellW: number,
592→  cellH: number,
593→): HTMLCanvasElement {
594→  const canvas = document.createElement("canvas");
595→  canvas.width = cellH;
596→  canvas.height = cellW;
597→  const ctx = canvas.getContext("2d");
598→  if (!ctx) return canvas;
599→  ctx.translate(cellH, 0);

600→  ctx.rotate(Math.PI / 2);
601→  ctx.drawImage(atlas, cellIndex * cellW, 0, cellW, cellH, 0, 0, cellW, cellH);
602→  return canvas;
603→}
