855→function composeBorderImageFromAtlas(atlas: HTMLImageElement): string {
856→  const cellW = atlas.width / 8;
857→  const cellH = atlas.height;
858→  const cell = Math.max(1, Math.floor(Math.min(cellW, cellH)));
859→  const canvas = document.createElement("canvas");
860→  canvas.width = cell * 3;
861→  canvas.height = cell * 3;
862→  const ctx = canvas.getContext("2d");
863→  if (!ctx) return "";
864→  ctx.clearRect(0, 0, canvas.width, canvas.height);
865→  ctx.imageSmoothingEnabled = false;
866→
867→  const drawCell = (idx: number, x: number, y: number) => {
868→    ctx.drawImage(atlas, idx * cellW, 0, cellW, cellH, x, y, cell, cell);
869→  };
870→
871→  drawCell(4, 0, 0);
872→  drawCell(5, cell * 2, 0);
873→  drawCell(6, 0, cell * 2);
874→  drawCell(7, cell * 2, cell * 2);
875→  drawCell(0, 0, cell);
876→  drawCell(1, cell * 2, cell);
877→
878→  const top = rotateCellClockwise(atlas, 2, cellW, cellH);
879→  const bottom = rotateCellClockwise(atlas, 3, cellW, cellH);
880→  ctx.drawImage(top, cell, 0, cell, cell);
881→  ctx.drawImage(bottom, cell, cell * 2, cell, cell);
882→
883→  return canvas.toDataURL("image/png");
884→}
